import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { formatDate } from './dateUtils'; // adjust path as needed

describe('formatDate', () => {
  it('should handle happy path', () => {
    const iso = '2023-08-15T12:34:56Z';
    const result = formatDate(iso);
    // Assuming the function returns a human readable format, e.g., "August 15, 2023"
    expect(result).toBeDefined();
    expect(typeof result).toBe('string');
    // Basic pattern check (month day, year)
    expect(result).toMatch(/^\w+ \d{1,2}, \d{4}$/);
  });

  it('should handle edge case', () => {
    // Leap year date
    const iso = '2024-02-29T00:00:00Z';
    const result = formatDate(iso);
    expect(result).toBeDefined();
    expect(result).toMatch(/^\w+ \d{1,2}, \d{4}$/);
  });

  it('should handle null/empty', () => {
    // Test with null
    expect(() => formatDate(null as any)).toThrow();
    // Test with undefined
    expect(() => formatDate(undefined as any)).toThrow();
    // Test with empty string
    expect(() => formatDate('')).toThrow();
    // Test with zero
    expect(() => formatDate(0 as any)).toThrow();
  });
});

